### Swift Enum Associated Values

Associated values allow enum cases to store additional custom data of any type. Each case can have different types of associated values, making enums extremely flexible for modeling state.

**Associated Values Syntax:**

```swift
enum Barcode {
    case upc(Int, Int, Int, Int)  // 4 associated values
    case qrCode(String)           // 1 associated value
}

var productBarcode = Barcode.upc(8, 85909, 51226, 3)
productBarcode = .qrCode("ABCDEFGHIJKLMNOP")

// Extract with switch
switch productBarcode {
case .upc(let numberSystem, let manufacturer, let product, let check):
    print("UPC: \(numberSystem)-\(manufacturer)-\(product)-\(check)")
case .qrCode(let code):
    print("QR Code: \(code)")
}
```

**Pattern Matching with Associated Values:**

```swift
// All let or all var can be placed before case
switch productBarcode {
case let .upc(numberSystem, manufacturer, product, check):
    print("UPC: \(numberSystem)")
case let .qrCode(code):
    print("QR: \(code)")
}

// Matching with conditions
enum NetworkResult {
    case success(data: [String: Any])
    case failure(error: String, code: Int)
}

let result = NetworkResult.failure(error: "Not found", code: 404)

switch result {
case .success(let data):
    print("Got data: \(data)")
case .failure(let error, let code) where code >= 500:
    print("Server error: \(error)")
case .failure(let error, _):
    print("Client error: \(error)")
}
```

**Practical Use Cases:**

| Pattern | Example |
|---------|---------|
| Result type | `.success(value)` / `.failure(error)` |
| Media types | `.image(Data)` / `.video(url)` |
| Form fields | `.text(String)` / `.number(Int)` |
| Network state | `.loading` / `.loaded(T)` |

```swift
enum Optional<T> {
    case none
    case some(T)
}

enum Either<Left, Right> {
    case left(Left)
    case right(Right)
}
```

> **Key Point:** Associated values make enums a powerful tool for modeling data. Each case can hold different types and amounts of associated data, like a discriminated union.

Use `if case let` syntax for matching a single case without switch:

```swift
if case let .success(data) = result {
    print("Success: \(data)")
}

guard case let .failure(error, _) = result else { return }
print("Error: \(error)")
```

codeExample:
import Foundation

enum PaymentMethod {
    case creditCard(number: String, cvv: String, expiry: String)
    case applePay(token: String)
    case bankTransfer(accountNumber: String, sortCode: String)
    case cash
}

func processPayment(_ payment: PaymentMethod) -> String {
    switch payment {
    case .creditCard(let number, _, _):
        let masked = String(number.suffix(4))
        return "Processing card ending in \(masked)"
    case .applePay:
        return "Processing Apple Pay"
    case .bankTransfer(let account, _):
        return "Processing transfer to account \(account)"
    case .cash:
        return "Processing cash payment"
    }
}

let payments: [PaymentMethod] = [
    .creditCard(number: "1234567890123456", cvv: "123", expiry: "12/26"),
    .applePay(token: "tok_abc123"),
    .cash
]

for payment in payments {
    print(processPayment(payment))
}

// If case let for single case matching
if case let .creditCard(number, _, _) = payments[0] {
    print("\nCard number: \(number)")
}
